begin
  --===========================================================
  --*** Reset generation ***
  proc_a_rst : process
  begin
    if a_rst_before_g then
      wait for 3 * a_period_c;
    else
      wait for 30 * a_period_c;
    end if;
    wait until rising_edge(a_clk_sti);
